{
    "level": "A2",
    "intro": "In this topic, you will learn the <strong>Present Simple Passive</strong>: how to form affirmatives, negatives, and questions in the present passive.",
    "rules": [
        {
            "label": "Formula",
            "color": "emerald",
            "text": "<strong>am/is/are + V3</strong>:",
            "example": "The letter is written."
        },
        {
            "label": "Denial",
            "color": "rose",
            "text": "<strong>am/is/are + not + V3</strong>:",
            "example": "The letter is not written."
        },
        {
            "label": "Question",
            "color": "blue",
            "text": "<strong>Am/Is/Are + S + V3?</strong>:",
            "example": "Is the letter written?"
        }
    ]
}

{
    "title": "1. Choosing am/is/are",
    "intro": "The verb <strong>be</strong> depends on the subject:",
    "items": [
        {
            "label": "I",
            "title": "am",
            "subtitle": "I am paid monthly."
        },
        {
            "label": "He/She/It",
            "title": "is",
            "subtitle": "It is made in China."
        },
        {
            "label": "You/We/They",
            "title": "are",
            "subtitle": "They are invited to the party."
        },
        {
            "label": "Plural nouns",
            "title": "are",
            "subtitle": "Cars are produced here."
        }
    ]
}

{
    "title": "2. Affirmative sentences",
    "sections": [
        {
            "label": "Structure",
            "color": "emerald",
            "description": "Порядок: <strong>Subject + am/is/are + V3 (+ by agent)</strong>",
            "examples": [
                {
                    "en": "English is spoken in many countries.",
                    "ua": "English is spoken in many countries."
                },
                {
                    "en": "The rooms are cleaned every day.",
                    "ua": "The rooms are cleaned every day."
                },
                {
                    "en": "I am paid at the end of each month.",
                    "ua": "I am paid at the end of each month."
                }
            ]
        },
        {
            "label": "When to use?",
            "color": "sky",
            "description": "For <strong>regular actions</strong>, <strong>general facts</strong> and <strong>habits</strong>:",
            "examples": [
                {
                    "en": "Coffee is grown in Brazil.",
                    "ua": "Coffee is grown in Brazil."
                },
                {
                    "en": "Newspapers are delivered every morning.",
                    "ua": "Newspapers are delivered every morning."
                },
                {
                    "en": "This road is used by many cars.",
                    "ua": "This road is used by many cars."
                }
            ]
        }
    ]
}

{
    "title": "3. Negative sentences",
    "sections": [
        {
            "label": "Structure",
            "color": "rose",
            "description": "Add <strong>not</strong> after am/is/are: <strong>Subject + am/is/are + not + V3</strong>",
            "examples": [
                {
                    "en": "The door is not locked.",
                    "ua": "The door is not locked."
                },
                {
                    "en": "These cars are not made in Japan.",
                    "ua": "These cars are not made in Japan."
                },
                {
                    "en": "I am not invited to the meeting.",
                    "ua": "I am not invited to the meeting."
                }
            ]
        },
        {
            "label": "Abbreviated forms",
            "color": "amber",
            "description": "<strong>isn't / aren't</strong> is used colloquially:",
            "examples": [
                {
                    "en": "The window isn't opened.",
                    "ua": "The window isn't opened."
                },
                {
                    "en": "The reports aren't finished yet.",
                    "ua": "The reports aren't finished yet."
                }
            ],
            "note": "The form <strong>am not</strong> is not shortened: I am not (I'm not)."
        }
    ]
}

{
    "title": "4. Interrogative sentences",
    "sections": [
        {
            "label": "Yes/No question",
            "color": "blue",
            "description": "<strong>Am/Is/Are</strong> comes out on top: <strong>Am/Is/Are + Subject + V3?</strong>",
            "examples": [
                {
                    "en": "Is English spoken here?",
                    "ua": "Is English spoken here?"
                },
                {
                    "en": "Are the rooms cleaned daily?",
                    "ua": "Are the rooms cleaned daily?"
                },
                {
                    "en": "Am I included in the list?",
                    "ua": "Am I included in the list?"
                }
            ]
        },
        {
            "label": "Wh question",
            "color": "sky",
            "description": "<strong>Wh-word + am/is/are + Subject + V3?</strong>",
            "examples": [
                {
                    "en": "Where is coffee grown?",
                    "ua": "Where is coffee grown?"
                },
                {
                    "en": "How often are the rooms cleaned?",
                    "ua": "How often are the rooms cleaned?"
                },
                {
                    "en": "Why is this product so popular?",
                    "ua": "Why is this product so popular?"
                }
            ]
        },
        {
            "label": "Short answers",
            "color": "amber",
            "description": "Answers with <strong>Yes/No + am/is/are (not)</strong>:",
            "examples": [
                {
                    "en": "Is the letter written? — Yes, it is. / No, it isn't.",
                    "ua": "Is the letter written? — Yes, it is. / No, it isn't."
                },
                {
                    "en": "Are they invited? — Yes, they are. / No, they aren't.",
                    "ua": "Are they invited? — Yes, they are. / No, they aren't."
                }
            ]
        }
    ]
}

{
    "title": "5. Active vs Passive: Present Simple",
    "intro": "Comparison of active and passive state:",
    "rows": [
        {
            "en": "Active: Tom writes letters every day.",
            "ua": "Active: Tom writes letters every day.",
            "note": "→ Passive: Letters are written every day."
        },
        {
            "en": "Active: They clean the rooms daily.",
            "ua": "Active: They clean the rooms daily.",
            "note": "→ Passive: The rooms are cleaned daily."
        },
        {
            "en": "Active: People speak English here.",
            "ua": "Active: People speak English here.",
            "note": "→ Passive: English is spoken here."
        }
    ],
    "warning": "📌 Time markers (every day, always, often) remain!"
}

{
    "title": "6. Typical mistakes",
    "items": [
        {
            "label": "Error 1",
            "color": "rose",
            "title": "The wrong choice is/are.",
            "wrong": "The letters is sent every day.",
            "right": "✅ The letters are sent every day."
        },
        {
            "label": "Error 2",
            "color": "amber",
            "title": "Skip be in the questions.",
            "wrong": "The room cleaned daily?",
            "right": "✅ Is the room cleaned daily?"
        },
        {
            "label": "Error 3",
            "color": "sky",
            "title": "Using V1 instead of V3.",
            "wrong": "English is speak here.",
            "right": "✅ English is spoken here."
        }
    ]
}

{
    "title": "Other pages from the basics of the passive voice",
    "items": [
        {
            "label": "What is Passive Voice?",
            "current": false
        },
        {
            "label": "Form: be + V3",
            "current": false
        },
        {
            "label": "Present Simple Passive (current)",
            "current": true
        },
        {
            "label": "Past Simple Passive",
            "current": false
        }
    ]
}
